import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import StatusBadge from '../components/workorders/StatusBadge';
import WODetailModal from '../components/workorders/WODetailModal';
import './Dashboard.css';

const STATS_BY_ROLE = {
  client: [
    { label: 'Open',         value: 24, sub: '+3 this week',   subCls: 'up'     },
    { label: 'In Progress',  value: 11, sub: '2 near SLA',     subCls: 'warn'   },
    { label: 'Closed',       value: 87, sub: 'this month',     subCls: ''       },
    { label: 'SLA Breaches', value: 2,  sub: 'needs action',   subCls: 'danger' },
  ],
  contractor: [
    { label: 'Assigned',         value: 8,  sub: 'to my team',     subCls: ''     },
    { label: 'In Progress',      value: 5,  sub: '1 near SLA',     subCls: 'warn' },
    { label: 'Completed',        value: 34, sub: 'this month',     subCls: 'up'   },
    { label: 'Pending Approval', value: 2,  sub: 'awaiting client', subCls: ''    },
  ],
  supervisor: [
    { label: 'My Tasks',     value: 6,  sub: '2 urgent',      subCls: 'warn'  },
    { label: 'Team Active',  value: 4,  sub: 'workmen',        subCls: ''      },
    { label: 'Pending QC',  value: 1,  sub: 'review needed',  subCls: 'warn'  },
    { label: 'Done Today',   value: 3,  sub: 'on track',       subCls: 'up'    },
  ],
  workman: [
    { label: 'Open Tasks',      value: 2, sub: '1 urgent',    subCls: 'warn' },
    { label: 'Completed Today', value: 1, sub: 'good pace',   subCls: 'up'   },
  ],
  enduser: [
    { label: 'My Requests', value: 3, sub: 'submitted',   subCls: ''   },
    { label: 'In Progress', value: 2, sub: 'being worked', subCls: ''   },
    { label: 'Resolved',    value: 8, sub: 'this month',  subCls: 'up' },
  ],
};

export default function Dashboard() {
  const { role, workOrders } = useApp();
  const navigate = useNavigate();
  const [selectedWO, setSelectedWO] = useState(null);

  const stats = STATS_BY_ROLE[role] || STATS_BY_ROLE.client;
  const recentWOs = workOrders.slice(0, 5);

  return (
    <div>
      {/* Stat cards */}
      <div className="stats-grid" style={{ gridTemplateColumns: `repeat(${stats.length}, 1fr)` }}>
        {stats.map(s => (
          <div className="stat-card" key={s.label}>
            <div className="stat-label">{s.label}</div>
            <div className="stat-value">{s.value}</div>
            <div className={`stat-sub ${s.subCls}`}>{s.sub}</div>
          </div>
        ))}
      </div>

      {/* Recent Work Orders */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">Recent work orders</span>
          <button className="btn btn-sm" onClick={() => navigate('/work-orders')}>View all</button>
        </div>
        <table className="data-table">
          <thead>
            <tr>
              <th>Work Order</th>
              <th>Contractor</th>
              <th>Priority</th>
              <th>Status</th>
              <th>Due</th>
            </tr>
          </thead>
          <tbody>
            {recentWOs.map(wo => (
              <tr key={wo.id} onClick={() => setSelectedWO(wo)}>
                <td>
                  <span style={{ fontSize:11, color:'var(--text-3)', display:'block' }}>{wo.id}</span>
                  <span style={{ fontWeight:500 }}>{wo.title}</span>
                </td>
                <td style={{ color:'var(--text-2)' }}>{wo.contractor}</td>
                <td className={`priority-${wo.priority.toLowerCase()}`}>{wo.priority}</td>
                <td><StatusBadge status={wo.status} /></td>
                <td style={{ color: wo.due === '27 Apr' ? 'var(--danger)' : 'var(--text-2)', fontWeight: wo.due === '27 Apr' ? 600 : 400 }}>
                  {wo.due === '27 Apr' ? 'Today' : wo.due}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* SLA Summary — client only */}
      {role === 'client' && (
        <div className="card">
          <div className="card-header">
            <span className="card-title">SLA Performance — April 2026</span>
          </div>
          <div className="card-body">
            <div className="sla-summary-grid">
              <div className="sla-kpi">
                <div className="sla-kpi-label">Within SLA</div>
                <div className="sla-kpi-value" style={{ color:'var(--success)' }}>94%</div>
                <div className="sla-kpi-sub">this month</div>
              </div>
              <div className="sla-kpi">
                <div className="sla-kpi-label">Avg Resolution</div>
                <div className="sla-kpi-value">5.2h</div>
                <div className="sla-kpi-sub">vs 6h target</div>
              </div>
              <div className="sla-kpi">
                <div className="sla-kpi-label">Breaches</div>
                <div className="sla-kpi-value" style={{ color:'var(--danger)' }}>2</div>
                <div className="sla-kpi-sub">requires action</div>
              </div>
              <div className="sla-kpi">
                <div className="sla-kpi-label">Top Contractor</div>
                <div className="sla-kpi-value" style={{ fontSize:18 }}>AlphaServ</div>
                <div className="sla-kpi-sub">4.8 ★ rating</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* WO Detail Modal */}
      {selectedWO && (
        <WODetailModal
          wo={workOrders.find(w => w.id === selectedWO.id)}
          onClose={() => setSelectedWO(null)}
        />
      )}
    </div>
  );
}
